using BgControls.Collections.Generic;namespace BgControls.Windows.Input.Touch;/// <summary>/// 触控辅助类，用于管理 UI 元素的触控事件处理程序和手势识别逻辑./// </summary>internal class TouchHelper{    private UIElement element;    private WeakReferenceList<TouchEventHandler> touchEnterHandlers;    private WeakReferenceList<TouchEventHandler> touchDownHandlers;    private WeakReferenceList<TouchEventHandler> touchMoveHandlers;    private WeakReferenceList<TouchEventHandler> touchUpHandlers;    private WeakReferenceList<TouchEventHandler> touchLeaveHandlers;    private WeakReferenceList<TouchEventHandler> lostTouchCaptureHandlers;    private GestureHelper? gestureHelper;    /// <summary>    /// Initializes a new instance of the <see cref="TouchHelper"/> class.    /// </summary>    /// <param name="element">关联的 UI 元素.</param>    internal TouchHelper(UIElement element)    {        // 检查参数是否为空.        ArgumentNullException.ThrowIfNull(element, nameof(element));        this.element = element;        this.touchEnterHandlers = new WeakReferenceList<TouchEventHandler>();        this.touchDownHandlers = new WeakReferenceList<TouchEventHandler>();        this.touchMoveHandlers = new WeakReferenceList<TouchEventHandler>();        this.touchUpHandlers = new WeakReferenceList<TouchEventHandler>();        this.touchLeaveHandlers = new WeakReferenceList<TouchEventHandler>();        this.lostTouchCaptureHandlers = new WeakReferenceList<TouchEventHandler>();        this.SuspendMouseMovesCount = 1;    }    /// <summary>    /// Gets or sets 滚动视图辅助工具.    /// </summary>    internal ScrollViewerHelper? ScrollViewerHelper { get; set; }    /// <summary>    /// Gets or sets 挂起鼠标移动事件的计数.    /// </summary>    internal int SuspendMouseMovesCount { get; set; }    /// <summary>    /// Gets 触控进入事件的处理程序列表.    /// </summary>    internal WeakReferenceList<TouchEventHandler> TouchEnterHandlers => this.touchEnterHandlers;    /// <summary>    /// Gets 触控按下事件的处理程序列表.    /// </summary>    internal WeakReferenceList<TouchEventHandler> TouchDownHandlers => this.touchDownHandlers;    /// <summary>    /// Gets 触控移动事件的处理程序列表.    /// </summary>    internal WeakReferenceList<TouchEventHandler> TouchMoveHandlers => this.touchMoveHandlers;    /// <summary>    /// Gets 触控抬起事件的处理程序列表.    /// </summary>    internal WeakReferenceList<TouchEventHandler> TouchUpHandlers => this.touchUpHandlers;    /// <summary>    /// Gets 触控离开事件的处理程序列表.    /// </summary>    internal WeakReferenceList<TouchEventHandler> TouchLeaveHandlers => this.touchLeaveHandlers;    /// <summary>    /// Gets 丢失触控捕获事件的处理程序列表.    /// </summary>    internal WeakReferenceList<TouchEventHandler> LostTouchCaptureHandlers => this.lostTouchCaptureHandlers;    /// <summary>    /// Gets or sets a value indicating whether 是否已建立触控订阅.    /// </summary>    internal bool IsTouchSubscriptionEstablished { get; set; }    /// <summary>    /// 获取或创建手势辅助工具.    /// </summary>    /// <returns>手势辅助工具实例，如果触控管理器未启用则返回 null.</returns>    internal GestureHelper? GetOrCreateGestureHelper()    {        // 检查全局触控管理器是否启用.        if (TouchManager.IsEnabled)        {            if (this.gestureHelper == null)            {                // 初始化手势辅助类并关联当前元素与辅助类实例.                this.gestureHelper = new GestureHelper(this.element, this);            }            return this.gestureHelper;        }        return null;    }    /// <summary>    /// 尝试获取已存在的手势辅助工具.    /// </summary>    /// <returns>手势辅助工具实例，可能返回 null.</returns>    internal GestureHelper? TryGetGestureHelper()    {        // 返回当前缓存的手势辅助对象.        return this.gestureHelper;    }}